export function getDashboardSettingsCopy(locale: Locale): string {
  return LEGAL_CONTENT[locale].dashboardSettingsCopy;
}

export function getFooterContent(locale: Locale): FooterContent {
  return LEGAL_CONTENT[locale].footer;
}

export function getHomeHero(locale: Locale): HomeHero {
  return LEGAL_CONTENT[locale].homeHero;
}

export function getHomeSummary(locale: Locale): string {
  return LEGAL_CONTENT[locale].homeSummary;
}

export function getLegalPageContent(slug: string, locale: Locale): LegalPageContent {
  return LEGAL_CONTENT[locale].pages[slug];
}

export function buildLegalMetadata(slug: string, locale: Locale) {
  const content = getLegalPageContent(slug, locale);
  return {
    title: `${content.title} | Moon Arcana`,
    description: content.description,
    alternates: {
      canonical: localizedUrl(locale, `/${slug}`),
      languages: buildLanguageAlternates(`/${slug}`),
    },
    robots: {
      index: true,
      follow: true,
    },
  };
}
